    // Evaluation state
    const [evaluation, setEvaluation] = useState<'excellent' | 'good' | 'needs_work' | null>(null);

    useEffect(() => {
        fetchSubmission();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [submissionId]);

    const fetchSubmission = async () => {
        try {
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) {
                router.push('/login');
                return;
            }

            const { data, error } = await supabase
                .from('homework_submissions')
                .select(`
                    id,
                    status,
                    created_at,
                    subject,
                    understanding_level,
                    event:events (title),
                    photos:homework_photos (id, photo_url, graded_photo_url, comment)
                `)
                .eq('id', submissionId)
                // Security check
                .eq('student_id', user.id)
                .single();

            if (error || !data) {
                console.error("Error fetching submission:", error);
                router.push('/dashboard');
                return;
            }

            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            setSubmission(data as any);

            // Set initial evaluation if already evaluated
            if (data.understanding_level) {
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                setEvaluation(data.understanding_level as any);
            }
        } catch (error) {
            console.error(error);
        } finally {
            setIsLoading(false);
        }
    };

    const handleSubmitEvaluation = async () => {
        if (!evaluation || !submission) return;

        setIsSubmitting(true);
        try {
            const { error } = await supabase
                .from('homework_submissions')
                .update({
                    understanding_level: evaluation,
                    status: 'returned' // Mark as fully completed
                })
                .eq('id', submission.id);

            if (error) throw error;

            // Update local state to reflect the change
            setSubmission({
                ...submission,
                status: 'returned',
                understanding_level: evaluation
            });

            // Re-fetch to be safe
            await fetchSubmission();
        } catch (error) {
            console.error("Evaluation failed:", error);
            alert("隧穂ｾ｡縺ｮ騾∽ｿ｡縺ｫ螟ｱ謨励＠縺ｾ縺励◆縲ゅｂ縺・ｸ蠎ｦ縺願ｩｦ縺励￥縺縺輔＞縲・

