                                {/* Body (Expandable) */}
                                {isExpanded && (
                                    <div className="px-5 md:px-6 pb-6 pt-2 border-t border-gray-50 dark:border-gray-800/50 bg-gray-50/50 dark:bg-gray-900/50">
