"use client";

import { useState } from "react";
import Link from "next/link";
import Image from "next/image";
import { Eye, EyeOff } from "lucide-react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { createClient } from "@/utils/supabase/client";
import { useRouter } from "next/navigation";

const signupSchema = z.object({
    email: z.string().email("譛牙柑縺ｪ繝｡繝ｼ繝ｫ繧｢繝峨Ξ繧ｹ繧貞・蜉帙＠縺ｦ縺上□縺輔＞"),
    password: z
        .string()
        .min(8, "8譁・ｭ嶺ｻ･荳翫〒蜈･蜉帙＠縺ｦ縺上□縺輔＞")
        .regex(/[A-Z]/, "螟ｧ譁・ｭ励ｒ1縺､莉･荳雁性繧√※縺上□縺輔＞")
        .regex(/[a-z]/, "蟆乗枚蟄励ｒ1縺､莉･荳雁性繧√※縺上□縺輔＞")
        .regex(/[0-9]/, "謨ｰ蟄励ｒ1縺､莉･荳雁性繧√※縺上□縺輔＞")
        .regex(/[^A-Za-z0-9]/, "險伜捷繧・縺､莉･荳雁性繧√※縺上□縺輔＞"),
    role: z.string().refine(val => ["student", "parent", "admin"].includes(val), { message: "蠖ｹ蜑ｲ繧帝∈謚槭＠縺ｦ縺上□縺輔＞" }),
    lastName: z.string().min(1, "蟋薙ｒ蜈･蜉帙＠縺ｦ縺上□縺輔＞").max(50, "50譁・ｭ嶺ｻ･蜀・〒蜈･蜉帙＠縺ｦ縺上□縺輔＞"),
    firstName: z.string().min(1, "蜷阪ｒ蜈･蜉帙＠縺ｦ縺上□縺輔＞").max(50, "50譁・ｭ嶺ｻ･蜀・〒蜈･蜉帙＠縺ｦ縺上□縺輔＞"),
    birthdate: z.string().optional(),
    gradeLevel: z.string().optional(),
    schoolName: z.string().max(100, "100譁・ｭ嶺ｻ･蜀・〒蜈･蜉帙＠縺ｦ縺上□縺輔＞").optional(),
    targetHighSchool: z.string().max(100, "100譁・ｭ嶺ｻ･蜀・〒蜈･蜉帙＠縺ｦ縺上□縺輔＞").optional(),
}).superRefine((data, ctx) => {
    if (data.role === "student") {
        if (!data.gradeLevel) {
            ctx.addIssue({ path: ["gradeLevel"], code: z.ZodIssueCode.custom, message: "蟄ｦ蟷ｴ繧帝∈謚槭＠縺ｦ縺上□縺輔＞" });
        }
        if (!data.birthdate) {
            ctx.addIssue({ path: ["birthdate"], code: z.ZodIssueCode.custom, message: "逕溷ｹｴ譛域律繧貞・蜉帙＠縺ｦ縺上□縺輔＞" });
        } else {
            const date = new Date(data.birthdate);
            if (date >= new Date()) {
                ctx.addIssue({ path: ["birthdate"], code: z.ZodIssueCode.custom, message: "驕主悉縺ｮ譌･莉倥ｒ蜈･蜉帙＠縺ｦ縺上□縺輔＞" });
            }
        }
    }
});

type FormData = z.infer<typeof signupSchema>;

export default function SignUpPage() {
    const router = useRouter();
    const [step, setStep] = useState(1);
    const [isLoading, setIsLoading] = useState(false);
    const [showPassword, setShowPassword] = useState(false);
    const [submitError, setSubmitError] = useState<string | null>(null);
    const totalSteps = 4;

    const {
        register,
        handleSubmit,
        trigger,
        watch,
        setValue,
        setError,
        formState: { errors }
    } = useForm<FormData>({
        resolver: zodResolver(signupSchema),
        defaultValues: {
            email: "",
            password: "",
            role: "",
            firstName: "",
            lastName: "",
            birthdate: "",
            gradeLevel: "",
            schoolName: "",
            targetHighSchool: "",
        },
        mode: "onChange",
    });

    const currentRole = watch("role");

    const validateStepAndProceed = async () => {
        let fieldsToValidate: any[] = [];
        if (step === 1) fieldsToValidate = ["email", "password"];
        if (step === 2) {
            if (!currentRole) {
                setError("role", { message: "蠖ｹ蜑ｲ繧帝∈謚槭＠縺ｦ縺上□縺輔＞" });
                return;
            }
            fieldsToValidate = ["role"];
        }
        if (step === 3) {
            if (currentRole === "student") {
                fieldsToValidate = ["lastName", "firstName", "birthdate", "gradeLevel", "schoolName", "targetHighSchool"];
            } else {
                fieldsToValidate = ["lastName", "firstName"];
            }
        }

        const isValid = await trigger(fieldsToValidate);
        if (isValid && step < totalSteps) {
            setStep(step + 1);
        }
    };

    const prevStep = () => {
        if (step > 1) setStep(step - 1);
    };

    const onSubmit = async (data: FormData) => {
        setIsLoading(true);
        setSubmitError(null);

        try {
            const supabase = createClient();

            // 1. Sign up the user via Supabase Auth
            // The handle_new_user trigger in the database will automatically create the profile row
            const { data: authData, error: authError } = await supabase.auth.signUp({
                email: data.email,
                password: data.password,
                options: {
                    data: {
                        role: data.role,
                        first_name: data.firstName,
                        last_name: data.lastName,
                        school_name: data.schoolName || null,
                        grade_level: data.gradeLevel || null,
                        birthdate: data.birthdate || null,
                        target_high_school: data.targetHighSchool || null,
                    }
                }
            });

            if (authError) {
                console.error("Signup error:", authError);
                setSubmitError(authError.message);
                return;
            }

            // Success - redirect to a confirmation page or home
            // For now, let's redirect to the signin page with a success parameter
            // In a real app with email confirmation enabled, tell them to check their email
            router.push("/signin?message=繧｢繧ｫ繧ｦ繝ｳ繝井ｽ懈・縺ｫ謌仙粥縺励∪縺励◆縲ゅΟ繧ｰ繧､繝ｳ縺励※縺上□縺輔＞縲・

min-h-screen flex items-center justify-c:
text-center mb-8">
                    {step === 1 && (
                        <div className="flex justify-center mb-6">
                            <Image
                                src="/lapis_icon.png"
                                alt="LapisStudy Icon"
                                width={64}
                                height={64}
                                className="w-16 h-16 drop-shadow-md"
                            />
                        </div>
