                    <h1 className="text-2xl md:text-3xl font-extrabold text-lapis-900 dark:text-lapis-50 mb-2 tracking-tight transition-all">
                        {step === 1 && "LapisStudy縺ｫ蜿ょ刈縺吶ｋ"}
                        {step === 2 && "蠖ｹ蜑ｲ繧呈蕗縺医※縺上□縺輔＞"}
                        {step === 3 && "繝励Ο繝輔ぅ繝ｼ繝ｫ蜈･蜉媾

student" && (
                                    <>
                                        {(watch("schoolName") || watch("gradeLevel")) && (
                                            <div>
                                                <div className="text-xs text-app-text2 dark:text-app-text2-dark">蟄ｦ譬｡繝ｻ蟄ｦ蟷ｴ</div>
