        { name: "縺ｧ縺阪◆総", value: stats.evaluations.good, color: "#3B82F6" },  // Blue 500
        { name: "縺後ｓ縺ｰ縺｣縺溟沐･", value: stats.evaluations.okay, color: "#F59E0B" }, // Amber 500
        { name: "隧穂ｾ｡蠕・■遲噂

